sql:
SELECT coach_name, experience
FROM coaches
WHERE experience = (SELECT MAX(experience) FROM coaches);

SELECT SUBSTR(coach_name, 1, 5) AS coach_initials
FROM coaches
WHERE team_id = (SELECT team_id FROM seasons WHERE champion_team_id = 1);

SELECT c.coach_id, c.coach_name
FROM coaches c
WHERE c.team_id = (
    SELECT s.champion_team_id
    FROM seasons s
    WHERE s.season_id = (
        SELECT MAX(season_id) FROM seasons
    )
);
